description:
Implement input capture that fixes the bash race condition:

```go
// input.go
package main

import (
    "fmt"
    "io"
    "os"
    "strings"
)

// CaptureInput reads all input from stdin or file arguments.
// CRITICAL: This MUST be called as the FIRST operation in main()
// before any other I/O to avoid the race condition that plagued bash.
func CaptureInput(args []string) (string, error) {
    // Check stdin FIRST - before any other operations
    stat, _ := os.Stdin.Stat()
    if (stat.Mode() & os.ModeCharDevice) == 0 {
        // Stdin is piped - read ALL immediately
        data, err := io.ReadAll(os.Stdin)
        if err != nil {
            return "", fmt.Errorf("reading stdin: %w", err)
        }
        return string(data), nil
    }

    // Fallback to file arguments
    if len(args) > 0 {
        var parts []string
        for _, f := range args {
            data, err := os.ReadFile(f)
            if err != nil {
                return "", fmt.Errorf("reading file %s: %w", f, err)
            }
            parts = append(parts, string(data))
        }
        return strings.Join(parts, "\n"), nil
    }

    return "", nil
}
```

Key requirements:
- io.ReadAll for deterministic capture
- Check stdin mode before reading
- Support file arguments as fallback
- Return empty string (not error) for no input
